#include <bits/stdc++.h> 
using namespace std;
const int N=10005,K=105,inf=0x3f3f3f3f;
int n,m,k,vis[N][K];
struct node
{
	int v,w;
	bool operator<(const node other) const
	{
		return w>other.w;
	}
};
vector<node> g[N];
void bfs()
{
	memset(vis,0x3f,sizeof(vis));
	vis[1][0]=0;
	priority_queue<node> q;
	q.push(node{1,0});
	while(!q.empty())
	{
		node t=q.top();
		q.pop();
		int u=t.v,tim=t.w;
		if(u==n&&tim%k==0) return ;
		for(int i=0;i<g[u].size();i++)
		{
			int v=g[u][i].v,w=g[u][i].w;
//			cout<<u<<" "<<v<<" : ";
//			if((w>tim)&&((w%k)!=(tim%k)))
//			{
//				cout<<"NO\n";
//				continue;
//			}
//			cout<<"YES\n";
			int nnum=((tim>=w)?(vis[u][tim%k]):(vis[u][tim%k]+(w-vis[u][tim%k]+k-1)/k*k))+1;
//			cout<<u<<" -> "<<v<<" "<<nnum<<'\n';
			if(vis[v][nnum%k]==inf) q.push(node{v,nnum});
			vis[v][nnum%k]=min(vis[v][nnum%k],nnum);
		}
	}
}
int main()
{
	cin>>n>>m>>k;
	for(int i=1;i<=m;i++)
	{
		int u,v,w;
		cin>>u>>v>>w;
		g[u].push_back(node{v,w});
	}
	bfs();
	if(vis[n][0]==inf) cout<<-1;
	else cout<<vis[n][0];
	return 0;
}
